  (void)Rte_Write_PpGearPosition_ShortTermAdjActiveFlag_b(s_ShortTermAdjActiveFlag_b);
  (void)Rte_Write_PpGearPosition_GearValue(s_GearPosForced_u8);
  return v_retvalue;
