      Rte_SWC_DIDMgr_DID_RearBrakeEvent_MirrorBlock.RearBrkEvent_Arr[Rte_SWC_DIDMgr_DID_RearBrakeEvent_MirrorBlock.BlockIdx_u8].StreeringWhlAngEvntStart_u16 = (uint16)v_LwsAngle_u16;
