      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].SideofVehicle_u8 = (uint8)ActiveSideDisaply.m_FpaInfoToVC.stFPALockedSlotData.m_SlotSide;
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].MeasuredSlotSize_u16 = (uint16)(ActiveSideDisaply.m_FpaInfoToVC.stFPALockedSlotData.Vertices[e_ZERO].y);
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].MeasuredSlotSize_u16 = (uint16)RIGHTSHIFT_BIT(Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].MeasuredSlotSize_u16, BIT_SHIFT_EIGHT_BIT);
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].MeasuredSlotSize_u16 = (uint16)((Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].MeasuredSlotSize_u16 * BIT_MASK_UPR) + ActiveSideDisaply.m_FpaInfoToVC.stFPALockedSlotData.Vertices[e_ZERO].x);
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].ExternalTemperature_u16 = (uint16)v_ExtTemp_u16;
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].CalculatedTireSize_u16 = (uint16)v_Tyrsz_u16;
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].NumofManeuvers_u8 = (uint8)ParkingManeuverPosition.IeAP_cnt_CurrentVehSweep;
      Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.SPMAbrtEvent_Arr[Rte_SWC_DIDMgr_DID_SPMAbrtEvent_MirrorBlock.BlockIdx_u8].AbortCnd_u8 = (uint8)ParkingData.IeAP_e_AbortCon;
